class Solution:
    def sortColors(self, nums: list[int]) -> None:
        lo, mid, hi = 0, 0, len(nums) - 1   # [0,lo)全是0,[lo,mid)全是1,(hi,末]全是2
        while mid <= hi:
            x = nums[mid]
            if x == 0:               # 0 换到前区
                nums[lo], nums[mid] = nums[mid], nums[lo]
                lo += 1; mid += 1
            elif x == 1:             # 1 留在中间
                mid += 1
            else:                    # 2 换到后区(换来的还没看,mid 不动)
                nums[mid], nums[hi] = nums[hi], nums[mid]
                hi -= 1
